package com.example.userapp.network;

import java.io.IOException;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

public class AuthInterceptor implements Interceptor {

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request originalRequest = chain.request();

        Request.Builder builder = originalRequest.newBuilder()
                .header("Accept", "application/json")
                .header("Content-Type", "application/json");

        // Add auth token if available
        String token = getAuthToken();
        if (token != null && !token.isEmpty()) {
            builder.header("Authorization", "Bearer " + token);
        }

        Request newRequest = builder.method(originalRequest.method(), originalRequest.body()).build();
        return chain.proceed(newRequest);
    }

    private String getAuthToken() {
        // TODO: Retrieve token from secure storage (SharedPreferences / EncryptedSharedPreferences)
        return null;
    }
}


