package com.example.userapp.repository;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import com.example.userapp.model.Resource;
import com.example.userapp.model.User;
import com.example.userapp.model.UserListResponse;
import com.example.userapp.network.ApiClient;
import com.example.userapp.network.ApiService;

import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class UserRepository {

    private static volatile UserRepository instance;
    private final ApiService apiService;

    private UserRepository() {
        apiService = ApiClient.getInstance().getApiService();
    }

    public static UserRepository getInstance() {
        if (instance == null) {
            synchronized (UserRepository.class) {
                if (instance == null) {
                    instance = new UserRepository();
                }
            }
        }
        return instance;
    }

    public LiveData<Resource<List<User>>> fetchUsers(int page, int perPage) {
        MutableLiveData<Resource<List<User>>> liveData = new MutableLiveData<>();
        liveData.setValue(Resource.loading());

        apiService.getUsers(page, perPage).enqueue(new Callback<UserListResponse>() {
            @Override
            public void onResponse(Call<UserListResponse> call, Response<UserListResponse> response) {
                if (response.isSuccessful() && response.body() != null) {
                    liveData.postValue(Resource.success(response.body().getData()));
                } else {
                    String errorMsg = "Error " + response.code() + ": " + parseErrorMessage(response);
                    liveData.postValue(Resource.error(errorMsg));
                }
            }

            @Override
            public void onFailure(Call<UserListResponse> call, Throwable t) {
                liveData.postValue(Resource.error("Network error: " + t.getMessage()));
            }
        });

        return liveData;
    }

    public LiveData<Resource<List<User>>> fetchAllUsers() {
        MutableLiveData<Resource<List<User>>> liveData = new MutableLiveData<>();
        liveData.setValue(Resource.loading());

        apiService.getAllUsers().enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    liveData.postValue(Resource.success(response.body()));
                } else {
                    String errorMsg = "Error " + response.code() + ": " + parseErrorMessage(response);
                    liveData.postValue(Resource.error(errorMsg));
                }
            }

            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                liveData.postValue(Resource.error("Network error: " + t.getMessage()));
            }
        });

        return liveData;
    }

    public LiveData<Resource<User>> fetchUserById(long userId) {
        MutableLiveData<Resource<User>> liveData = new MutableLiveData<>();
        liveData.setValue(Resource.loading());

        apiService.getUserById(userId).enqueue(new Callback<User>() {
            @Override
            public void onResponse(Call<User> call, Response<User> response) {
                if (response.isSuccessful() && response.body() != null) {
                    liveData.postValue(Resource.success(response.body()));
                } else {
                    String errorMsg = "Error " + response.code() + ": " + parseErrorMessage(response);
                    liveData.postValue(Resource.error(errorMsg));
                }
            }

            @Override
            public void onFailure(Call<User> call, Throwable t) {
                liveData.postValue(Resource.error("Network error: " + t.getMessage()));
            }
        });

        return liveData;
    }

    private String parseErrorMessage(Response<?> response) {
        try {
            if (response.errorBody() != null) {
                return response.errorBody().string();
            }
        } catch (Exception e) {
            // Ignore parse errors
        }
        return "Unknown error";
    }
}


