package com.example.userapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MediatorLiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.userapp.model.Resource;
import com.example.userapp.model.User;
import com.example.userapp.repository.UserRepository;

import java.util.List;

public class UserViewModel extends ViewModel {

    private final UserRepository userRepository;
    private final MediatorLiveData<Resource<List<User>>> usersLiveData = new MediatorLiveData<>();
    private final MediatorLiveData<Resource<User>> userDetailLiveData = new MediatorLiveData<>();
    private final MutableLiveData<Boolean> isRefreshing = new MutableLiveData<>(false);

    public UserViewModel() {
        userRepository = UserRepository.getInstance();
    }

    public LiveData<Resource<List<User>>> getUsersLiveData() {
        return usersLiveData;
    }

    public LiveData<Resource<User>> getUserDetailLiveData() {
        return userDetailLiveData;
    }

    public LiveData<Boolean> getIsRefreshing() {
        return isRefreshing;
    }

    public void loadUsers(int page, int perPage) {
        LiveData<Resource<List<User>>> source = userRepository.fetchUsers(page, perPage);
        usersLiveData.addSource(source, resource -> {
            usersLiveData.setValue(resource);
            if (resource.getStatus() != Resource.Status.LOADING) {
                usersLiveData.removeSource(source);
                isRefreshing.setValue(false);
            }
        });
    }

    public void loadAllUsers() {
        LiveData<Resource<List<User>>> source = userRepository.fetchAllUsers();
        usersLiveData.addSource(source, resource -> {
            usersLiveData.setValue(resource);
            if (resource.getStatus() != Resource.Status.LOADING) {
                usersLiveData.removeSource(source);
                isRefreshing.setValue(false);
            }
        });
    }

    public void loadUserById(long userId) {
        LiveData<Resource<User>> source = userRepository.fetchUserById(userId);
        userDetailLiveData.addSource(source, resource -> {
            userDetailLiveData.setValue(resource);
            if (resource.getStatus() != Resource.Status.LOADING) {
                userDetailLiveData.removeSource(source);
            }
        });
    }

    public void refreshUsers() {
        isRefreshing.setValue(true);
        loadAllUsers();
    }
}


