package com.example.userapp.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout;

import com.example.userapp.BuildConfig;
import com.example.userapp.R;
import com.example.userapp.model.Resource;
import com.example.userapp.ui.adapter.UserAdapter;
import com.example.userapp.viewmodel.UserViewModel;

public class MainActivity extends AppCompatActivity {

    private UserViewModel userViewModel;
    private UserAdapter userAdapter;
    private RecyclerView recyclerView;
    private ProgressBar progressBar;
    private TextView tvError;
    private TextView tvEmpty;
    private SwipeRefreshLayout swipeRefreshLayout;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        setTitle("Users (" + getEnvironmentLabel() + ")");

        initViews();
        setupRecyclerView();
        setupViewModel();
        setupSwipeRefresh();

        userViewModel.loadAllUsers();
    }

    private void initViews() {
        recyclerView = findViewById(R.id.recycler_view_users);
        progressBar = findViewById(R.id.progress_bar);
        tvError = findViewById(R.id.tv_error);
        tvEmpty = findViewById(R.id.tv_empty);
        swipeRefreshLayout = findViewById(R.id.swipe_refresh_layout);
    }

    private void setupRecyclerView() {
        userAdapter = new UserAdapter();
        recyclerView.setLayoutManager(new LinearLayoutManager(this));
        recyclerView.setAdapter(userAdapter);

        userAdapter.setOnUserClickListener(user -> {
            Intent intent = new Intent(MainActivity.this, UserDetailActivity.class);
            intent.putExtra(UserDetailActivity.EXTRA_USER_ID, user.getId());
            intent.putExtra(UserDetailActivity.EXTRA_USER_NAME, user.getName());
            startActivity(intent);
        });
    }

    private void setupViewModel() {
        userViewModel = new ViewModelProvider(this).get(UserViewModel.class);

        userViewModel.getUsersLiveData().observe(this, resource -> {
            if (resource == null) return;

            switch (resource.getStatus()) {
                case LOADING:
                    showLoading();
                    break;
                case SUCCESS:
                    hideLoading();
                    if (resource.getData() != null && !resource.getData().isEmpty()) {
                        showUsers();
                        userAdapter.setUsers(resource.getData());
                    } else {
                        showEmpty();
                    }
                    break;
                case ERROR:
                    hideLoading();
                    showError(resource.getMessage());
                    break;
            }
        });

        userViewModel.getIsRefreshing().observe(this, isRefreshing -> {
            if (swipeRefreshLayout != null) {
                swipeRefreshLayout.setRefreshing(Boolean.TRUE.equals(isRefreshing));
            }
        });
    }

    private void setupSwipeRefresh() {
        swipeRefreshLayout.setOnRefreshListener(() -> userViewModel.refreshUsers());
    }

    private void showLoading() {
        progressBar.setVisibility(View.VISIBLE);
        recyclerView.setVisibility(View.GONE);
        tvError.setVisibility(View.GONE);
        tvEmpty.setVisibility(View.GONE);
    }

    private void hideLoading() {
        progressBar.setVisibility(View.GONE);
        swipeRefreshLayout.setRefreshing(false);
    }

    private void showUsers() {
        recyclerView.setVisibility(View.VISIBLE);
        tvError.setVisibility(View.GONE);
        tvEmpty.setVisibility(View.GONE);
    }

    private void showError(String message) {
        tvError.setVisibility(View.VISIBLE);
        tvError.setText(message != null ? message : "An unexpected error occurred");
        recyclerView.setVisibility(View.GONE);
        tvEmpty.setVisibility(View.GONE);
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }

    private void showEmpty() {
        tvEmpty.setVisibility(View.VISIBLE);
        recyclerView.setVisibility(View.GONE);
        tvError.setVisibility(View.GONE);
    }

    private String getEnvironmentLabel() {
        String baseUrl = BuildConfig.BASE_URL;
        if (baseUrl.contains("dev")) return "DEV";
        if (baseUrl.contains("staging")) return "STAGING";
        return "PROD";
    }
}


