// =========================================================

package com.example.userapp.ui;

import android.os.Bundle;
import android.view.MenuItem;
import android.view.View;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import com.example.userapp.R;
import com.example.userapp.model.User;
import com.example.userapp.viewmodel.UserViewModel;

public class UserDetailActivity extends AppCompatActivity {

    public static final String EXTRA_USER_ID = "extra_user_id";
    public static final String EXTRA_USER_NAME = "extra_user_name";

    private UserViewModel userViewModel;
    private ProgressBar progressBar;
    private TextView tvDetailName;
    private TextView tvDetailEmail;
    private TextView tvDetailPhone;
    private TextView tvDetailCreatedAt;
    private TextView tvError;
    private View contentLayout;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_user_detail);

        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
        }

        String userName = getIntent().getStringExtra(EXTRA_USER_NAME);
        setTitle(userName != null ? userName : "User Detail");

        initViews();
        setupViewModel();

        long userId = getIntent().getLongExtra(EXTRA_USER_ID, -1);
        if (userId != -1) {
            userViewModel.loadUserById(userId);
        } else {
            showError("Invalid user ID");
        }
    }

    private void initViews() {
        progressBar = findViewById(R.id.progress_bar_detail);
        tvDetailName = findViewById(R.id.tv_detail_name);
        tvDetailEmail = findViewById(R.id.tv_detail_email);
        tvDetailPhone = findViewById(R.id.tv_detail_phone);
        tvDetailCreatedAt = findViewById(R.id.tv_detail_created_at);
        tvError = findViewById(R.id.tv_detail_error);
        contentLayout = findViewById(R.id.layout_detail_content);
    }

    private void setupViewModel() {
        userViewModel = new ViewModelProvider(this).get(UserViewModel.class);

        userViewModel.getUserDetailLiveData().observe(this, resource -> {
            if (resource == null) return;

            switch (resource.getStatus()) {
                case LOADING:
                    progressBar.setVisibility(View.VISIBLE);
                    contentLayout.setVisibility(View.GONE);
                    tvError.setVisibility(View.GONE);
                    break;
                case SUCCESS:
                    progressBar.setVisibility(View.GONE);
                    contentLayout.setVisibility(View.VISIBLE);
                    tvError.setVisibility(View.GONE);
                    if (resource.getData() != null) {
                        bindUser(resource.getData());
                    }
                    break;
                case ERROR:
                    progressBar.setVisibility(View.GONE);
                    contentLayout.setVisibility(View.GONE);
                    showError(resource.getMessage());
                    break;
            }
        });
    }

    private void bindUser(User user) {
        tvDetailName.setText(user.getName() != null ? user.getName() : "N/A");
        tvDetailEmail.setText(user.getEmail() != null ? user.getEmail() : "N/A");
        tvDetailPhone.setText(user.getPhone() != null ? user.getPhone() : "N/A");
        tvDetailCreatedAt.setText(user.getCreatedAt() != null ? user.getCreatedAt() : "N/A");
    }

    private void showError(String message) {
        tvError.setVisibility(View.VISIBLE);
        tvError.setText(message != null ? message : "An error occurred");
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }

    @Override
    public boolean onOptionsItemSelected(MenuItem item) {
        if (item.getItemId() == android.R.id.home) {
            onBackPressed();
            return true;
        }
        return super.onOptionsItemSelected(item);
    }
}


